" Error handling pattern in AMDP
METHOD process_with_error_info
    BY DATABASE PROCEDURE FOR HDB
    LANGUAGE SQLSCRIPT OPTIONS READ-ONLY
    USING vbak.
  DECLARE lv_count INT := 0;
  lt_data = SELECT vbeln FROM vbak
            WHERE mandt = :iv_mandt
              AND erdat >= :iv_from_date;
  SELECT COUNT(*) INTO lv_count FROM :lt_data;
  IF :lv_count = 0 THEN
    -- SQLScript SIGNAL for error condition
    SIGNAL SQL_ERROR_CODE 10001
      SET MESSAGE_TEXT = 'No orders found for given date';
  END IF;
  et_result = SELECT * FROM :lt_data;
ENDMETHOD.
